__CPROVER_requires(
  arr ==> __CPROVER_is_fresh(arr, size))
__CPROVER_requires(
  arr_fun ==> __CPROVER_obeys_contract(arr_fun, arr_fun_contract))
__CPROVER_assigns(arr && size > 0 && arr_fun : arr[0])
__CPROVER_ensures(__CPROVER_return_value ==> (arr[0] == 0))
{
